var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":" 레이디스~~~! 앤, 젠틀맨~~~!","JPN":"レディース～～～！　アンド、ジェントルマン～～～！","ENG":"Ladies and gentlemen!","TWN":"Ladies～～～！ and Gentlemen～～～！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":" 알파트릭스에서 주최하는 포뮬러 원 챔피언십에 잘 오셨습니다!","JPN":"アルファトリックス主催の、フォーミュラ・ワン・チャンピオンシップにようこそ！","ENG":"Welcome to the Formula One Championship, sponsored by Alphatrix!","TWN":"歡迎來到阿爾法崔克斯主辦的F1錦標賽！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" 오늘은 그 기념비적인 첫 번째 레이스!","JPN":"本日はその記念すべき1回目のレース！","ENG":"And today is our first day of racing!","TWN":"今天是歷史性的第一場競賽！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":" 과연 오늘 레이스는 어떤 선수가 우승컵을 거머쥐게 될까요?","JPN":"果たして本日のレースを制覇し、トロフィーをその手にするのは、どの選手でしょうか。","ENG":"Who will be the champion of today’s race?","TWN":"究竟哪位選手能在今天的比賽中奪下冠軍獎盃呢？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" 하하, 관중석의 뜨거운 열기가 여기까지 전해지는군요!","JPN":"はは、客席の熱い熱気がここまで伝わってくるようですね！","ENG":"The crowd is cheering with excitement!","TWN":"哈哈哈～在這邊都能感受到觀眾的熱情呢！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":" 그렇다면, 오늘 레이스를 기획하고 주최하신 분을 모시지 않을 수 없겠죠?","JPN":"それでは、本日のレースの企画立案者であり主催者でもある、あの方をお呼びしてみましょう。","ENG":"Now, let me introduce the person who brought this race to you.","TWN":"那就趕緊讓我們邀請今天比賽的主辦方出場吧？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":" 미모와 지성을 겸비한 알파트릭스 엔터테인먼트의 대표~~!","JPN":"美貌と知性を併せ持つ、アルファトリックスエンターテインメントの代表～～！","ENG":"The beautiful and intelligent CEO of Alphatrix Entertainment!","TWN":"她就是美貌與智慧兼具的，阿爾法崔克斯娛樂代表～～！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":" 신세아 대표님을 모시겠습니다!","JPN":"ヒメノ・アイ代表です！","ENG":"Shin Seah!","TWN":"掌聲歡迎「沈玥」沈代表！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 우와~ 사람들이 정말 많네요. 떠들썩해서 어쩐지 즐거운 분위기에요.","JPN":"わあ～　すごい人の数ですね。賑やかで楽しそうです。","ENG":"Wow, so many people here today. I’m glad to be a part of it.","TWN":"哇～好多人喔。吵吵鬧鬧的，感覺好熱鬧喔。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 잠깐만 리더~! 그러니까, 우리 자리가 어디라고?","JPN":"ちょっと、リーダー！　私たちの席はどこだっけ？","ENG":"Wait, leader! What’s our seat number?","TWN":"先等一下，老大！我說，我們的座位在哪裡？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 으음, 어디 보자. G열에…","JPN":"そうですね。えーと、G列の……","ENG":"Let me see... It’s line G...","TWN":"嗯，我看一下喔，在G列…"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" …G열? ","JPN":"……G列？","ENG":"Line G?","TWN":"…G列？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" G열이면 정반대로 왔잖아!?","JPN":"G列って、真逆じゃない！","ENG":"We went to the opposite side!","TWN":"G列不是在反方向嗎！？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 아하, 그렇구나. 일반석은 알파벳이랑 숫자 순서대로 자리가 배치되는군요.","JPN":"なるほど、一般席はアルファベットと数字の組み合わせで席が配置されているのですね。","ENG":"Oh, I understand now. Standard seats have alphabets and numbers.","TWN":"哈，原來如此。原來一般席的座位安排是照著字母和數字的順序。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 일반석에 앉아 본 적이 없어서, 무심코 VIP석으로 와버렸네요.","JPN":"一般席に座ったことがなかったので、つい癖でVIP席の方に来てしまいました。","ENG":"I never sat in a standard seat before, I went to the VIP section without realizing it.","TWN":"因為我沒坐過一般席，不小心就走到VIP席的位置了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 아니, 그보다 친척 언니가 준 초청장이라면서?","JPN":"親戚のお姉さんにもらった招待状なんでしょ？","ENG":"You said your cousin gave you the tickets.","TWN":"問題是，這不是老大親姊姊給的邀請函嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 보통 주최자가 직접 준 티켓이 이렇게 경기장이랑 멀리 떨어진 자리를 준다고?","JPN":"主催者に直接貰ったチケットなのに、スタジアムからこんなにも離れた席ってありえるの？","ENG":"And it looks like she gave you the worst seat! How could she do that to you?","TWN":"通常主辦方親自安排的座位會離跑道那麼遠嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 네? 원래 그러면 안 되는 건가요?","JPN":"え？　なにか変ですか？","ENG":"Hm? Is there any reason that she shouldn’t?","TWN":"是的，這樣是不合理的嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 어머, 여기 있었구나. 지아야.","JPN":"あら、ここにいたのね。ユイ。","ENG":"Oh, hello, Jia.","TWN":"喔！沈佳，原來你在這裡。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 앗, 언니! 오래간만이에요!","JPN":"あっ、お姉様！　お久しぶりです。","ENG":"Oh, hi! How have you been?","TWN":"姊姊！好久不見！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 여기서 만날 줄은 몰랐네. 너한테 보낸 초청장의 좌석 티켓이 잘못 들어갔다고 들었는데.","JPN":"ここで会えるなんて思わなかったわ。あんたに送った招待状のチケットに誤りがあったと聞いたけど。","ENG":"I didn’t expect to see you here. I heard you got the wrong tickets.","TWN":"沒想到會在這裡見到你，我聽說給你的邀請函上寫的座位是錯的。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 아마 직원 측에서 실수가 있었던 모양이야.","JPN":"おそらく職員のほうでミスがあったみたい。","ENG":"It seems my secretary made a mistake.","TWN":"應該是員工搞錯了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 그런 일이 있었군요. 저는 괜찮아요. 그래도 이렇게 초대해주셨잖아요?","JPN":"そうですか。私は大丈夫です。招待してもらっただけでも嬉しいので。","ENG":"I see. I’m okay. Still, you invited me like this.","TWN":"原來是這樣，沒關係，反正我還是來啦。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그야 가족이니까. 가끔은 이렇게 얼굴도 보고 지내는 거지.","JPN":"家族だもの。たまにはこうして顔を合わせないとね。","ENG":"We’re family. That’s what family does.","TWN":"我們好歹也是一家人，偶爾也要像這樣見見面嘛！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 아, 그만 가봐야겠다. 아직 인사 나눠야 할 사람들이 많아서 말이야. 너도 이해하지?","JPN":"あ、そろそろ行かなきゃ。まだ挨拶回りが終わってないの。わかってくれるよね？","ENG":"I have to go now. There are others waiting for me. You understand that, do you?","TWN":"哎呀，我要先走了，還得去跟其他人打招呼呢，你也懂的嘛？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":"그럼 좋은 시간되렴.","JPN":"それでは、楽しんで。","ENG":"Have a good time, then.","TWN":"那你就好好欣賞比賽吧！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 네, 언니.","JPN":"はい、お姉様。","ENG":"You too.","TWN":"謝謝姊姊。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAFF_NPC_ALPHA_RACING","text":{"KOREA":" 대표님!! 큰일 났습니다!!","JPN":"代表！！　大変です！！","ENG":"Madam! We have a problem!","TWN":"代表！！不好了！！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 이, 이게 대체…","JPN":"こ、これはいったい……","ENG":"What the...","TWN":"這…這是怎麼回事…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STAFF_NPC_ALPHA_RACING","text":{"KOREA":" 창고에 쌓여 있던 적재물이 갑자기 무너졌습니다.","JPN":"倉庫に積んであった積載物が突然崩れました。","ENG":"The rows of stock in the warehouse just collapsed.","TWN":"堆在倉庫裡的東西突然倒塌，"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAFF_NPC_ALPHA_RACING","text":{"KOREA":" 그래서 아래에 있던 총감독이랑 마샬 플래그가 깔렸고요.","JPN":"それで下にいた総監督とマーシャルが下敷きになったようです｡","ENG":"They fell in on the director and the flag marshal.","TWN":"結果壓到在底下的總監和賽車寶貝！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAFF_NPC_ALPHA_RACING","text":{"KOREA":" 생명에는 지장 없지만, 두 사람 다 중상입니다.","JPN":"命に別状はないそうですが､二人とも重症です。","ENG":"It wasn’t lethal, but both of them are seriously hurt.","TWN":"他們雖然沒有生命危險，但受到了重傷。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 난데없이 자재가 무너져서 두 사람이 깔렸다고?","JPN":"いきなり資材が崩れて二人が下敷きになったって？","ENG":"The rows just collapsed on them?","TWN":"東西突然就倒下來壓到他們？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …빌어먹을, 그걸 지금 나보고 믿으라는 거야? 경기 시작까지 고작 30분 남았다고!","JPN":"……ふざけないで、そんな冗談を信じろと？　試合が始まるまでもう30分しかないのよ！","ENG":"Do you want me to believe that? The race starts in thirty minutes!","TWN":"…該死的，現在距離比賽開始只剩30分鐘，你要我相信這種事？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STAFF_NPC_ALPHA_RACING","text":{"KOREA":" 그, 그렇지만…","JPN":"で、ですが……","ENG":"But...","TWN":"可…可是…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …철제 선반을 지지하고 있던 프레임에 절단된 흔적이 있네요.","JPN":"……鉄製棚を支えていたフレームに切断された跡があります。","ENG":"Hey, look at this shelf. It’s a clean cut.","TWN":"…這個鐵架的支架有被人截斷的痕跡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 용병 솜씨에요, 이거.","JPN":"傭兵の仕業ですね。","ENG":"I think it was a mercenary.","TWN":"看起來是出自傭兵之手。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …용병?","JPN":"……傭兵？","ENG":"A mercenary?","TWN":"…傭兵？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 설마, 신재혁 그 개자식이…?","JPN":"まさか、ヒメノ・ダイチ、あのくそ野郎が……？","ENG":"Could it be that bastard Shin Jaehyuk...?","TWN":"難道是沈赫那傢伙幹的好事…？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …아, 맞아!!","JPN":"……そうだ！！","ENG":"Oh, yes!","TWN":"…有了！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 지아야! 나 좀 도와줘!","JPN":"ユイ、ちょっと手伝ってちょうだい！","ENG":"Jia, you have to help me!","TWN":"沈佳！我需要你！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 네?","JPN":"え？","ENG":"Huh?","TWN":"什麼事？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그래! 지아가 비주얼이 되니까, 네가 <color=#ffd34c>플래그 마샬</color>을 맡으면 되겠다.","JPN":"そうよ！　ユイは顔がいいから、<color=#ffd34c>フラッグマーシャル</color>にぴったりだわ。","ENG":"Yes, you’re pretty, you’d make a great <color=#ffd34c>flag marshal</color>!","TWN":"沒錯！你的外型很OK，就由你來擔任<color=#ffd34c>賽車寶貝</color>的角色吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 응, 응!! 대박인데!? 그러면 사람들의 주목을 한 눈에 받을 거야!","JPN":"うん！！　いいじゃない！　これで注目されること間違いなしだわ！","ENG":"Yes, yes! That’s a great idea! Everyone will be looking at you!","TWN":"沒錯！我真是太聰明了！大家一定會一眼就注意到你！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 그치만 전 한 번도 해본 적 없는데요?","JPN":"でも、私はそんなこと一度もやったことがありません……","ENG":"But I’ve never done that before.","TWN":"可是我沒經驗？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" <color=#ff3636>뭔 헛소리야, 넌 뭐든지 잘하잖아.</color>","JPN":"<color=#ff3636>何を言ってるの、あんたはなんだってできるでしょ？</color>","ENG":"<color=#ff3636>Stop bs’ing me, you’re great at everything.</color>","TWN":"<color=#ff3636>說什麼傻話，你不是什麼都很厲害嗎！</color>"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그리고 당신, 눈썰미가 꽤 나쁘지 않던데. 당신이 <color=#ffd34c>오피셜</color>을 좀 맡아 줘야겠어.","JPN":"それからあんた、いい目をしてるようね。あんたには<color=#ffd34c>オフィシャル</color>になってもらうわ。","ENG":"And you. You have a good eye. I want you to be the race <color=#ffd34c>official</color>.","TWN":"而且，你的眼力也很不錯，那就也身兼一下<color=#ffd34c>裁判</color>吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 보수라면 얼마든지 주지.","JPN":"報酬ならいくらでも払うから。","ENG":"I’ll pay you whatever you ask.","TWN":"報酬的話你儘管開口！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …리더, 어떻게 할까요?","JPN":"……リーダー、どうしましょう？","ENG":"Leader, what shall we do now?","TWN":"…老大，你怎麼說？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 할아버님께서 가르쳐주셨어요. 가족이라면 서로 돕고 살아야 한다고요.","JPN":"お祖父様はこう言いました。家族は助け合うものだと。","ENG":"My grandfather said a family should help each other.","TWN":"我爺爺有說，一家人要互相幫忙。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 네. 알겠습니다.","JPN":"はい。了解しました。","ENG":"Okay.","TWN":"好，收到。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":" 경기 시작했습니다!","JPN":"試合が始まりました！","ENG":"The race has begun!","TWN":"比賽開始！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_18"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":" …야야! 저기 깃발 든 사람 좀 봐!","JPN":"……ちょっと！　あの旗を持ってる人、見て！","ENG":"Hey, look at the girl with the flag!","TWN":"…喂！你看那個舉牌的人！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_RACING_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":" 우왓, 대박이네! 어디서 저런 연예인을 섭외했대? 돈 좀 썼나 봐?","JPN":"うわ、すごいな！　どこであんな芸能人を呼んだんだ？　金がかかってるな！","ENG":"Wow, she’s amazing! I didn’t know they had a model here! Must have been costly!","TWN":"哇賽，超強！去哪請來那種藝人等級的正妹的，看來花了不少錢喔？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_RACING_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 좋아, 예상대로 신지아가 잘 해주고 있군.","JPN":"いいわ、予想どおりユイがうまくやってくれてる。","ENG":"Good, Shin Jia is doing great.","TWN":"很好，跟我想的一樣，沈佳做得很好。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 이대로라면, 오늘 레이스는 문제없겠어.","JPN":"このままいけば、今日のレースは無事終わるわ。","ENG":"The race will be a huge success if we go on like this.","TWN":"這樣今天的比賽應該可以順利結束。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 아직 안심하기는 이를 텐데요.","JPN":"まだ安心するには早いですよ。","ENG":"Don’t lower your guard yet.","TWN":"還不到安心的時候。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 뭐라고?","JPN":"何ですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 중지되었어야 할 레이스가 계속 진행되었으니, 공작원들도 다시 움직일 겁니다.","JPN":"中止されるはずだったレースが続行されたことで、工作員もまた動きだすでしょう。","ENG":"What they wanted was to stop the event. They will strike again until they succeed.","TWN":"既然比賽順利進行，那些人一定也不會善罷甘休。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …확실히.","JPN":"……確かに。","ENG":"You’re right.","TWN":"…說的有道理。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그럼 어떻게 해야 하지?","JPN":"では、どうすればいいの？","ENG":"What should we do then?","TWN":"那現在該怎麼辦呢？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 이런 일을 맡는 용병들은 보통 효율성을 가장 먼저 생각하죠.","JPN":"こういう仕事を任された傭兵は普通、効率性を最優先します。","ENG":"Mercenaries who take this sort of job always prioritize efficiency first.","TWN":"會幹這種事的傭兵，通常最先考慮到的都是效率。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 대회를 멈추려면 사람을 다치게 하는 정도로는 안 된다는 걸 알았으니 더 과감한 공작수단을 가져올 겁니다.","JPN":"人が怪我をしたくらいでは大会を止められないと知り、より過激な手段に出るでしょう。","ENG":"Now that they’ve realized hurting a couple of people won’t stop the event, they will try even more drastic measures.","TWN":"既然有人受傷也無法阻止比賽繼續，那很可能會採取更激烈的手段。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 건물을 무너뜨린다거나 전력을 끊어버리는 식으로 말이죠.","JPN":"たとえば建物を壊す、電力を遮断するなどです。","ENG":"Such as destroying a building, or cutting the power.","TWN":"像是使建築物倒塌或是切斷電源。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 출입인원에 대한 보안을 강화하고, 주요기반시설들의 위치를 알려주세요. 나머지는 저희가 해결하겠습니다.","JPN":"人の出入りに対するセキュリティーを強化し、主要基盤施設の位置を教えてください。あとはこっちで解決します。","ENG":"Raise the level of security at the entrance, and give me the layout of major facilities in this vicinity. I’ll handle the rest.","TWN":"請加強出入管制，然後告訴我主要設施的位置，剩下的我們會處理。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …조, 좋아.","JPN":"わ……わかったわ。","ENG":"Oh, okay.","TWN":"…喔…好。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그런데 그 괴물은 그렇다 쳐도, 당신은 왜 이렇게까지 날 돕는 거야?","JPN":"ところで、あの化け物はいいとして、あんたはなんで私を手伝うの？","ENG":"Setting the monster aside, why are you helping me?","TWN":"可是那個怪物願意幫我也就算了，你們為什麼要幫我？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 최선을 다하는 것뿐입니다. 의뢰는 책임이 곧 생명이니까요.","JPN":"最善を尽くしているだけです。依頼において責任感は命なので。","ENG":"I’m just doing my best. This is a mission, and I’m taking my responsibilities seriously.","TWN":"我們只是盡我所能而已，既然受人之託就要負責到底。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":" 젠장, 추가보수도 못 받는데 귀찮게 하는군.","JPN":"くそ、追加報酬もないのに、面倒かけやがって。","ENG":"Damn, I’m not getting paid enough for this.","TWN":"該死！又沒拿到額外津貼，現在還搞得這麼麻煩！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":" 이제 슬슬 터뜨려볼까?","JPN":"そろそろ爆発させるか？","ENG":"Okay, let’s blow it now.","TWN":"就是現在引爆嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":" …음? 지하에 웬 허수아비가… ","JPN":"……ん？　なんで地下にかかしが……？","ENG":"Huh? What is a scarecrow doing in the basement...?","TWN":"…嗯？地下室怎麼會有稻草人…"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":" 으아아악?!","JPN":"うわああっ！","ENG":"Argh!","TWN":"呃啊啊啊？！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":" 여기는 가브리엘.","JPN":"こちらガブリエル。","ENG":"This is Gabriel.","TWN":"這裡是加布里埃爾。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":" 지하실에서 폭발물 소지자를 제압했다.","JPN":"地下室にて爆発物の所持者を制圧した。","ENG":"I neutralized a man armed with explosives.","TWN":"已經在地下室壓制住炸彈客。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 좋아, 가브리엘. 다음 포인트로 이동 후, 대기.","JPN":"了解です。ガブリエル、次のポイントまで移動し、待機してください。","ENG":"Good job, Gabriel. Now move on to the next point and stand by.","TWN":"很好，加布里埃爾，請移動到下一個地點待命。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L27_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 거기 안 서?!","JPN":"待ってよ！！","ENG":"Hey, stop!","TWN":"還不給我站住？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":" 너 같으면 서겠냐?","JPN":"待てと言われて待つバカがいるかよ！","ENG":"Do you think I’ll listen to you?","TWN":"你要是我～你會站住嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 여기는 오새롬!","JPN":"こちらアサネ！","ENG":"This is Oh Saerom!","TWN":"這裡是吳芷倫！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L34_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 객석에서 어슬렁거리는 나쁜 녀석을 쓰러트렸어! 이 녀석, 기름통을 가지고 있더라고!","JPN":"客席をうろつく悪い奴を倒したよ！　こいつ、ガソリン容器を持ってた！","ENG":"I got a bad guy in the stands! He had a can of oil with him!","TWN":"抓到在觀眾席中亂晃的壞人了！他竟然帶著汽油桶！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHOWON_ALPHA_RACING_NULL","text":{"KOREA":" 잘했어. 구속해서 본부로 데려와.","JPN":"お見事です。拘束して本部に連れてきてください。","ENG":"Good. Bring him back to the headquarters.","TWN":"非常好，把他綁起來帶回總部。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_RACING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 오늘 정말 고마워, 지아야.","JPN":"今日は本当にありがとう、ユイ。","ENG":"Thank you very much, Jia.","TWN":"沈佳，今天真的很謝謝。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 너희 덕분에 무사히 레이스를 마칠 수 있었어.","JPN":"あんたたちのおかげで無事、レースを終えることができたわ。","ENG":"We finished the day’s racing without further issues thanks to you.","TWN":"都是因為有你們的幫忙，比賽才能夠順利結束。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 아니에요. 전 오히려 재미있었는 걸요?","JPN":"とんでもないです。私はむしろ楽しかったですよ。","ENG":"You’re welcome. It was fun.","TWN":"別這麼說，我反而玩得很開心呢～"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그래? 그렇다면 다행이네.","JPN":"そう？　ならよかった。","ENG":"Really? It’s good to hear that.","TWN":"是嗎？那就好！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":" 훗, 자매간의 뜨거운 우애로군.","JPN":"ふっ、微笑ましい兄弟愛だな。","ENG":"It’s heartwarming to see sisterly love.","TWN":"呵，這就是所謂的姊妹情深嗎！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":" 가브리엘, 너는 좀 가만히 있어.","JPN":"ガブリエル、あなたはちょっと黙ってて。","ENG":"Gabriel, shut up.","TWN":"加布里埃爾，你閉嘴啦！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" …….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …아! 지아야.","JPN":"……あ！　ユイ。","ENG":"Oh, Jia.","TWN":"…那個，沈佳！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 별 건 아니고, 초원 씨랑 할 말 좀 있는데, 자리 좀 비켜줄래?","JPN":"大したことではないんだけど、ナオさんと少し話がしたくて。席を外してくれる？","ENG":"I have to talk to Chowon, will you excuse us for a moment?","TWN":"沒什麼，你可以讓我單獨跟初源說幾句話嗎？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":" 아하, 네! 편히 이야기 나누세요.","JPN":"もちろんです！　どうぞごゆっくり。","ENG":"Oh, of course. Take your time.","TWN":"喔喔～好的！你們慢慢聊。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 할 말이라는 게 뭐죠?","JPN":"話ってなんですか？","ENG":"What is it?","TWN":"要跟我說什麼？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …초원 씨. 지아한테 얼마씩 받으면서 일해?","JPN":"……ナオさんって、ユイからいくらもらってるの？","ENG":"Chowon. How much does Jia pay you?","TWN":"…初源，沈佳用多少錢請你的？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 잠깐, 조사해봤는데, 자기 용병 출신이더라?","JPN":"ちょっと調べさせてもらったけど、あなた、傭兵出身なんですって？","ENG":"I know you’re a mercenary. I’ve done my homework, you see.","TWN":"我有調查過，你是傭兵出身嗎？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 솔직히 그 괴물 밑에서 일하는 거 별로지? 귀찮은 일만 잔뜩 떠맡고 말이야.","JPN":"ぶっちゃけ、あの化け物の下で働くのって大変でしょ？　面倒ごとばかり押し付けられて。","ENG":"Do you like working for that monster? I know she can be a bother.","TWN":"老實說，在那怪物底下做事很討厭吧？一堆麻煩事要處理。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …어때, 자기? 내 밑에서 일해보는 건? 지아가 주는 돈에 2배…","JPN":"……どう？　私の下で働いてみない？　ユイが払っている金額の2倍……","ENG":"How about you come and work for me? I’ll pay you double...","TWN":"…如何？你願意到我這邊做事嗎？我可以出比沈佳高2倍…"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 아니, 5배까지 쳐줄 테니까.","JPN":"いや、5倍支払うわ。","ENG":"No, actually, I’m willing to pay you five times more.","TWN":"不，我願意出5倍！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 거절하죠.","JPN":"お断りします。","ENG":"I refuse.","TWN":"我拒絕。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 응? 왜?","JPN":"えっ？　どうして？","ENG":"Huh? Why?","TWN":"什麼？為什麼？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 페이가 부족한 거야?","JPN":"額が足りないの？","ENG":"The money’s not enough?","TWN":"5倍還太少嗎？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 그래, 10배까지 쳐줄게. 뒷자리에 0이 하나 더 붙는 거라고.","JPN":"いいわ、10倍でどう？　ゼロが一個増えるのよ。","ENG":"Okay, ten times, then. Imagine all the money you can have.","TWN":"那不然10倍吧！直接在後面多加個0！"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 아뇨, 페이 문제는 아니에요. 다만…","JPN":"いいえ、額の問題ではありません。ただ……","ENG":"No, it’s not about the money. It’s just that...","TWN":"不，不是錢的問題，是…"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …다만?","JPN":"ただ……？","ENG":"What is it?","TWN":"…是什麼問題？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 용병질에겐 신용이 생명이거든요.","JPN":"傭兵は信用が命なので。","ENG":"Trust is essential for a mercenary.","TWN":"對傭兵來說，信用跟他的性命一樣重要。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" 응?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼意思？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 다시 말해, 고작 이런 작은 행사조차 제대로 컨트롤 하지 못해서, 동생의 손을 빌리는 사람한테 제 등을 맡길 수는 없다는 말입니다.","JPN":"つまり、こんな小規模のイベント一つまともにコントロールできず、従妹の手を借りるような人に私の背を預けるわけにはいかないということです。","ENG":"You couldn’t even handle a small event like this, so you had to ask your little cousin for help. I cannot trust someone like you with my life.","TWN":"意思就是，我不願意把我的性命，交給一個連一個小小的活動都弄不好，還要靠妹妹出手的人手上。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ENTERTAINMENTCEO_NPC_ALPHA_NULL","text":{"KOREA":" …뭐, 뭐라고?","JPN":"……な、なんですって？","ENG":"W-what?","TWN":"…你…你說什麼？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 할 말 끝나셨으면, 가봐도 될까요?","JPN":"話が済んだのなら、帰ってもいいでしょうか？","ENG":"May I go, if you’re done?","TWN":"你話說完了嘛？我可以離開了吧？"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 함께 하는 내내 찜찜했고… 앞으로 다시 볼 일은 없으면 좋겠네요.","JPN":"あなたと一緒にいる間、ずっと気まずかったです。もう会うことはないといいですね。","ENG":"It was a very uncomfortable mission... and I hope I never see you again.","TWN":"和你相處的時間不是很愉快…希望我們以後不會再見面。"},"stage":{"bg":"RACING_CIRCUIT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};